// ── Formatters ────────────────────────────────────────────────────────────
const fmtPct = (v) => {
  if (v == null || isNaN(v)) return '--';
  const pct = v > 1 ? v : v * 100;
  return `${pct.toFixed(1)}%`;
};

const fmtNum = (v, d = 2) => {
  if (v == null || isNaN(v)) return '--';
  return Number(v).toFixed(d);
};

const fmt$ = (v) => {
  if (v == null || isNaN(v)) return '--';
  return new Intl.NumberFormat('en-US', {
    style: 'currency', currency: 'USD',
    minimumFractionDigits: 0, maximumFractionDigits: 0,
  }).format(v);
};

const fmtDate = (d) => {
  if (!d) return '--';
  try {
    return new Date(d).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  } catch { return d; }
};

// ── Direction helpers ─────────────────────────────────────────────────────
const dirColor = (dir) => {
  if (!dir) return C.textSecondary;
  const d = dir.toLowerCase();
  if (d === 'long') return C.green;
  if (d === 'short') return C.red;
  return C.blue;
};

const dirBg = (dir) => {
  if (!dir) return C.surface2;
  const d = dir.toLowerCase();
  if (d === 'long') return 'rgba(34,197,94,0.12)';
  if (d === 'short') return 'rgba(239,68,68,0.12)';
  return 'rgba(96,165,250,0.12)';
};

