// ── Star rating display ─────────────────────────────────────────────────
function Stars({ rating, count, size = 14 }) {
  const filled = Math.round(rating || 0);
  return (
    <div className={s.starsRow}>
      <div className={s.starsIcons}>
        {[1, 2, 3, 4, 5].map((i) => (
          <svg key={i} width={size} height={size} viewBox="0 0 20 20" fill="none">
            <path
              d="M10 1.5l2.47 5.01L18 7.27l-4 3.9.94 5.5L10 14.14l-4.94 2.53.94-5.5-4-3.9 5.53-.76L10 1.5z"
              fill={i <= filled ? C.amber : 'rgba(255,255,255,0.08)'}
              stroke={i <= filled ? C.amber : 'rgba(255,255,255,0.15)'}
              strokeWidth="0.5"
            />
          </svg>
        ))}
      </div>
      <span className={s.starRatingValue}>
        {rating ? fmtNum(rating, 1) : '0.0'}
      </span>
      {count != null && (
        <span className={s.starRatingCount}>({count})</span>
      )}
    </div>
  );
}

