// ── SVG Equity Curve ────────────────────────────────────────────────────
function EquityCurve({ data, width = 600, height = 200 }) {
  if (!data || data.length < 2) {
    return (
      <div className={s.equityCurveEmpty} style={{ height }}>
        No equity curve data
      </div>
    );
  }

  const values = data.map((d) => d.pnl ?? d.equity ?? 0);
  const min = Math.min(...values);
  const max = Math.max(...values);
  const range = max - min || 1;
  const pad = 20;
  const chartW = width - pad * 2;
  const chartH = height - pad * 2;

  const points = values.map((v, i) => {
    const x = pad + (i / (values.length - 1)) * chartW;
    const y = pad + chartH - ((v - min) / range) * chartH;
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  });

  const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p}`).join(' ');
  const isPositive = values[values.length - 1] >= values[0];
  const color = isPositive ? C.green : C.red;

  const areaD = `${pathD} L${(pad + chartW).toFixed(1)},${(pad + chartH).toFixed(1)} L${pad},${(pad + chartH).toFixed(1)} Z`;

  const gridLines = [];
  for (let i = 0; i <= 4; i++) {
    const y = pad + (chartH / 4) * i;
    const val = max - (range / 4) * i;
    gridLines.push({ y, val });
  }

  return (
    <svg width="100%" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="xMidYMid meet">
      <defs>
        <linearGradient id="eqGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.25" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      {gridLines.map((g, i) => (
        <g key={i}>
          <line
            x1={pad} y1={g.y} x2={pad + chartW} y2={g.y}
            stroke="rgba(255,255,255,0.04)" strokeWidth="1"
          />
          <text
            x={pad - 4} y={g.y + 3}
            fill={C.textSecondary} fontSize="9" fontFamily={mono}
            textAnchor="end"
          >
            {fmt$(g.val)}
          </text>
        </g>
      ))}
      <path d={areaD} fill="url(#eqGrad)" />
      <path d={pathD} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" />
      {min < 0 && max > 0 && (
        <line
          x1={pad}
          y1={pad + chartH - ((0 - min) / range) * chartH}
          x2={pad + chartW}
          y2={pad + chartH - ((0 - min) / range) * chartH}
          stroke="rgba(255,255,255,0.15)" strokeWidth="1" strokeDasharray="4,4"
        />
      )}
    </svg>
  );
}

// ── Select dropdown ─────────────────────────────────────────────────────
function Select({ value, onChange, options, placeholder, style }) {
  return (
    <select
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className={s.select}
      style={style}
    >
      {placeholder && <option value="">{placeholder}</option>}
      {options.map((o) => (
        <option key={typeof o === 'string' ? o : o.value} value={typeof o === 'string' ? o.toLowerCase() : o.value}>
          {typeof o === 'string' ? o : o.label}
        </option>
      ))}
    </select>
  );
}

// ── Text input ──────────────────────────────────────────────────────────
function Input({ value, onChange, placeholder, style, type = 'text' }) {
  return (
    <input
      type={type}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      className={s.input}
      style={style}
    />
  );
}

// ── Button ──────────────────────────────────────────────────────────────
function Btn({ children, onClick, variant = 'primary', disabled, style }) {
  const classMap = {
    primary: s.btnPrimary,
    secondary: s.btnSecondary,
    danger: s.btnDanger,
    green: s.btnGreen,
  };
  return (
    <motion.button
      whileTap={{ scale: 0.97 }}
      onClick={onClick}
      disabled={disabled}
      className={classMap[variant] || classMap.primary}
      style={style}
    >
      {children}
    </motion.button>
  );
}

// ── Tab button ──────────────────────────────────────────────────────────
function TabBtn({ label, active, onClick }) {
  return (
    <motion.button
      whileTap={{ scale: 0.97 }}
      onClick={onClick}
      className={active ? s.tabBtnActive : s.tabBtn}
    >
      {label}
    </motion.button>
  );
}

// ── Modal backdrop ──────────────────────────────────────────────────────
function Modal({ open, onClose, title, children, width = 720 }) {
  if (!open) return null;
  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className={s.modalOverlay}
      >
        <motion.div
          initial={{ opacity: 0, y: 20, scale: 0.97 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 20, scale: 0.97 }}
          transition={{ duration: 0.2 }}
          onClick={(e) => e.stopPropagation()}
          className={s.modalContent}
          style={{ maxWidth: width }}
        >
          {/* Modal header */}
          <div className={s.modalHeader}>
            <h2 className={s.modalTitle}>{title}</h2>
            <button onClick={onClose} className={s.modalCloseBtn} aria-label="Close dialog">x</button>
          </div>
          {/* Modal body */}
          <div className={s.modalBody}>
            {children}
          </div>
        </motion.div>
      </motion.div>
    </AnimatePresence>
  );
}

